import React from 'react';
import { motion } from 'framer-motion';
import { useInView } from 'react-intersection-observer';

const Skills = () => {
  const [ref, inView] = useInView({
    triggerOnce: true,
    threshold: 0.2,
  });

  const skillCategories = [
    {
      icon: '🎨',
      title: 'Design Tools',
      skills: ['Figma', 'Adobe Creative Suite', 'Illustrator', 'Photoshop', 'InDesign', 'Google Suite', 'Procreate'],
    },
    {
      icon: '🔬',
      title: 'UX/UI Methods',
      skills: ['Wireframing', 'Prototyping', 'Responsive Web/Mobile', 'Usability Testing', 'Design Systems'],
    },
    {
      icon: '🤖',
      title: 'AI in Design',
      skills: ['AI-driven Research', 'Brand Strategy', 'Content Generation', 'Rapid Prototyping', 'Workflow Optimization'],
    },
    {
      icon: '📊',
      title: 'Strategy',
      skills: ['Human-Centered Design', 'Design Thinking', 'Journey Mapping', 'Storytelling', 'Content Strategy'],
    },
    {
      icon: '💻',
      title: 'Platforms',
      skills: ['WordPress', 'WIX', 'Email Marketing', 'SEO'],
    },
    {
      icon: '👥',
      title: 'Leadership',
      skills: ['Client Presentations', 'Workshop Facilitation', 'Team Mentoring', 'Stakeholder Management', 'Design Strategy'],
    },
  ];

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1,
      },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: {
      opacity: 1,
      y: 0,
      transition: {
        duration: 0.5,
        ease: 'easeOut',
      },
    },
  };

  const tagVariants = {
    hidden: { opacity: 0, scale: 0.8 },
    visible: {
      opacity: 1,
      scale: 1,
      transition: {
        duration: 0.3,
      },
    },
  };

  return (
    <section className="skills section" id="skills">
      <div className="container">
        <motion.h2
          className="section-title"
          initial={{ opacity: 0, y: 20 }}
          animate={inView ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
          transition={{ duration: 0.5 }}
        >
          Core Skills
        </motion.h2>

        <motion.div
          ref={ref}
          className="skills-grid"
          variants={containerVariants}
          initial="hidden"
          animate={inView ? 'visible' : 'hidden'}
        >
          {skillCategories.map((category, index) => (
            <motion.div
              className="skill-category"
              key={index}
              variants={itemVariants}
              whileHover={{ y: -5 }}
            >
              <div className="skill-category-header">
                <div className="skill-icon">{category.icon}</div>
                <h3>{category.title}</h3>
              </div>
              <motion.div
                className="skill-tags"
                variants={containerVariants}
              >
                {category.skills.map((skill, i) => (
                  <motion.span
                    className="skill-tag"
                    key={i}
                    variants={tagVariants}
                    whileHover={{ scale: 1.05, backgroundColor: '#FFD000' }}
                  >
                    {skill}
                  </motion.span>
                ))}
              </motion.div>
            </motion.div>
          ))}
        </motion.div>
      </div>
    </section>
  );
};

export default Skills;
